// WorkOrderServiceServer is the server API for WorkOrderService service.
// All implementations must embed UnimplementedWorkOrderServiceServer
// for forward compatibility.
//
// WorkOrderService owns work orders, line items, the pricing menu, and time tracking (M3 + M4 + M5).
type WorkOrderServiceServer interface {
	CreateWorkOrder(context.Context, *CreateWorkOrderRequest) (*WorkOrder, error)
	GetWorkOrder(context.Context, *GetWorkOrderRequest) (*WorkOrder, error)
	AddLineItem(context.Context, *AddLineItemRequest) (*WorkOrder, error)
	RemoveLineItem(context.Context, *RemoveLineItemRequest) (*WorkOrder, error)
	TransitionState(context.Context, *TransitionStateRequest) (*WorkOrder, error)
	AssignMechanic(context.Context, *AssignMechanicRequest) (*WorkOrder, error)
	AssignLineItem(context.Context, *AssignLineItemRequest) (*WorkOrder, error)
	StartTimer(context.Context, *StartTimerRequest) (*TimeEntry, error)
	StopTimer(context.Context, *StopTimerRequest) (*TimeEntry, error)
	ListMenuItems(context.Context, *ListMenuItemsRequest) (*ListMenuItemsResponse, error)
	CreateMenuItem(context.Context, *CreateMenuItemRequest) (*MenuItem, error)
	UpdateMenuItem(context.Context, *UpdateMenuItemRequest) (*MenuItem, error)
	ListMenuPriceHistory(context.Context, *ListMenuPriceHistoryRequest) (*ListMenuPriceHistoryResponse, error)
	ListWorkOrders(context.Context, *ListWorkOrdersRequest) (*ListWorkOrdersResponse, error)
	// Per-shop pricing policy (currently the negotiated-discount cap).
	GetShopSettings(context.Context, *GetShopSettingsRequest) (*ShopSettings, error)
	UpdateShopSettings(context.Context, *UpdateShopSettingsRequest) (*ShopSettings, error)
	// Parts inventory.
	ListParts(context.Context, *ListPartsRequest) (*ListPartsResponse, error)
	CreatePart(context.Context, *CreatePartRequest) (*Part, error)
	AdjustStock(context.Context, *AdjustStockRequest) (*Part, error)
	// Appointments / scheduling.
	ListAppointments(context.Context, *ListAppointmentsRequest) (*ListAppointmentsResponse, error)
	CreateAppointment(context.Context, *CreateAppointmentRequest) (*Appointment, error)
	SetAppointmentState(context.Context, *SetAppointmentStateRequest) (*Appointment, error)
	// Per-work-order audit trail.
	GetAuditLog(context.Context, *GetAuditLogRequest) (*GetAuditLogResponse, error)
	// Service reminders (next oil change, inspection due, etc.).
	ListServiceReminders(context.Context, *ListServiceRemindersRequest) (*ListServiceRemindersResponse, error)
	CreateServiceReminder(context.Context, *CreateServiceReminderRequest) (*ServiceReminder, error)
	SetServiceReminderState(context.Context, *SetServiceReminderStateRequest) (*ServiceReminder, error)
	// Cross-shop due-queries + dedup, used by the notification scheduler to push reminders.
	ListDueReminders(context.Context, *ListDueRemindersRequest) (*ListServiceRemindersResponse, error)
	MarkReminderNotified(context.Context, *MarkNotifiedRequest) (*MarkNotifiedResponse, error)
	ListDueAppointments(context.Context, *ListDueAppointmentsRequest) (*ListAppointmentsResponse, error)
	MarkAppointmentReminded(context.Context, *MarkNotifiedRequest) (*MarkNotifiedResponse, error)
	// Shop overhead expenses + profit-and-loss.
	ListShopExpenses(context.Context, *ListShopExpensesRequest) (*ListShopExpensesResponse, error)
	CreateShopExpense(context.Context, *CreateShopExpenseRequest) (*ShopExpense, error)
	DeleteShopExpense(context.Context, *DeleteShopExpenseRequest) (*DeleteShopExpenseResponse, error)
	GetProfitAndLoss(context.Context, *GetProfitAndLossRequest) (*ProfitAndLoss, error)
	// Warranties on completed work (months / km coverage per vehicle).
	ListWarranties(context.Context, *ListWarrantiesRequest) (*ListWarrantiesResponse, error)
	CreateWarranty(context.Context, *CreateWarrantyRequest) (*Warranty, error)
	VoidWarranty(context.Context, *VoidWarrantyRequest) (*Warranty, error)
	// Customer estimate approval via a shareable token (e.g. a Telegram deep link).
	CreateApprovalLink(context.Context, *CreateApprovalLinkRequest) (*ApprovalLink, error)
	ResolveApproval(context.Context, *ResolveApprovalRequest) (*ApprovalInfo, error)
	DecideApproval(context.Context, *DecideApprovalRequest) (*ApprovalInfo, error)
	mustEmbedUnimplementedWorkOrderServiceServer()
}

